(window.webpackJsonp=window.webpackJsonp||[]).push([[73],{545:function(t,e,n){"use strict";n.r(e);var r=n(0),o=Object(r.a)({},(function(){return this._self._c("ContentSlotsDistributor",{attrs:{"slot-key":this.$parent.slotKey}},[this._self._c("div",{domProps:{innerHTML:"<p>&lt;div class=&quot;custom-block tip&quot;&gt;&lt;p class=&quot;custom-block-title&quot;&gt;摘要&lt;/p&gt;\n3D 场景渲染性能直接影响用户体验。本文总结了在数字孪生项目中实践的多种 Three.js 性能优化手段，包括场景选择性清理、按需加载策略、GPU 实例化渲染、帧率控制等，帮助大屏与 3D 模型联动场景实现流畅运行。\n&lt;/div&gt;</p>\n<h2>一、性能瓶颈分析</h2>\n<p>在包含 100+ 设备模型的 3D 机房场景中，常见的性能瓶颈有：</p>\n<ul>\n<li><strong>Draw Call 过多</strong>：每个独立 Mesh 都会产生一次 Draw Call</li>\n<li><strong>几何体顶点数过高</strong>：高精度模型的面数可能达到数十万</li>\n<li><strong>纹理内存占用大</strong>：4K 纹理每张约占用 64MB 显存</li>\n<li><strong>实时阴影开销</strong>：Shadow Map 的计算非常消耗 GPU</li>\n</ul>\n<h3>使用 Stats.js 监控性能</h3>\n<pre><code class=\"language-javascript\">import Stats from 'three/examples/jsm/libs/stats.module'\n\nconst stats = new Stats()\nstats.showPanel(0) // 0: FPS, 1: MS, 2: MB\ndocument.body.appendChild(stats.dom)\n\nfunction animate() {\n  stats.begin()\n  renderer.render(scene, camera)\n  stats.end()\n  requestAnimationFrame(animate)\n}\n</code></pre>\n<h2>二、几何体与材质优化</h2>\n<h3>1. 合并几何体减少 Draw Call</h3>\n<pre><code class=\"language-javascript\">import { mergeGeometries } from 'three/examples/jsm/utils/BufferGeometryUtils'\n\nconst geometries = []\nscene.traverse((child) =&gt; {\n  if (child.isMesh &amp;&amp; child.userData.type === 'floor') {\n    const geo = child.geometry.clone()\n    geo.applyMatrix4(child.matrixWorld)\n    geometries.push(geo)\n  }\n})\n\nconst mergedGeo = mergeGeometries(geometries)\nconst mergedMesh = new THREE.Mesh(mergedGeo, floorMaterial)\nscene.add(mergedMesh)\n</code></pre>\n<h3>2. InstancedMesh 实例化渲染</h3>\n<pre><code class=\"language-javascript\">// 相同型号服务器使用实例化\nconst count = serverPositions.length\nconst instancedMesh = new THREE.InstancedMesh(geometry, material, count)\nconst matrix = new THREE.Matrix4()\n\nserverPositions.forEach((pos, i) =&gt; {\n  matrix.setPosition(pos.x, pos.y, pos.z)\n  instancedMesh.setMatrixAt(i, matrix)\n})\n\ninstancedMesh.instanceMatrix.needsUpdate = true\nscene.add(instancedMesh)\n// Draw Call 从 100+ 降到 1\n</code></pre>\n<h3>3. 纹理优化</h3>\n<pre><code class=\"language-javascript\">// 压缩纹理尺寸\nconst textureLoader = new THREE.TextureLoader()\nconst texture = textureLoader.load('/textures/device.jpg')\ntexture.minFilter = THREE.LinearMipmapLinearFilter\ntexture.generateMipmaps = true\ntexture.anisotropy = renderer.capabilities.getMaxAnisotropy()\n\n// 使用 KTX2 压缩纹理格式\nimport { KTX2Loader } from 'three/examples/jsm/loaders/KTX2Loader'\nconst ktx2Loader = new KTX2Loader()\n  .setTranscoderPath('/basis/')\n  .detectSupport(renderer)\n</code></pre>\n<h2>三、渲染策略优化</h2>\n<h3>1. 按需渲染</h3>\n<p>场景静止时不需要持续渲染，可以节省大量 GPU 资源：</p>\n<pre><code class=\"language-javascript\">let needsRender = true\n\ncontrols.addEventListener('change', () =&gt; { needsRender = true })\n\nfunction animate() {\n  requestAnimationFrame(animate)\n  if (needsRender) {\n    renderer.render(scene, camera)\n    labelRenderer.render(scene, camera)\n    needsRender = false\n  }\n}\n</code></pre>\n<h3>2. 帧率限制</h3>\n<p>大屏项目通常不需要 60fps，限制到 30fps 可以减少一半 GPU 负载：</p>\n<pre><code class=\"language-javascript\">let lastTime = 0\nconst targetFPS = 30\nconst frameInterval = 1000 / targetFPS\n\nfunction animate(currentTime) {\n  requestAnimationFrame(animate)\n  const delta = currentTime - lastTime\n  if (delta &lt; frameInterval) return\n  lastTime = currentTime - (delta % frameInterval)\n\n  controls.update()\n  renderer.render(scene, camera)\n}\n</code></pre>\n<h3>3. 视锥体剔除</h3>\n<p>Three.js 默认开启视锥体剔除，但自定义逻辑可以更进一步：</p>\n<pre><code class=\"language-javascript\">const frustum = new THREE.Frustum()\nconst projScreenMatrix = new THREE.Matrix4()\n\nfunction updateVisibility() {\n  projScreenMatrix.multiplyMatrices(\n    camera.projectionMatrix,\n    camera.matrixWorldInverse\n  )\n  frustum.setFromProjectionMatrix(projScreenMatrix)\n\n  deviceModels.forEach((model) =&gt; {\n    model.visible = frustum.containsPoint(model.position)\n  })\n}\n</code></pre>\n<h2>四、内存管理</h2>\n<p>3D 场景最容易出现内存泄漏，组件卸载时必须彻底清理：</p>\n<pre><code class=\"language-javascript\">function disposeScene() {\n  scene.traverse((child) =&gt; {\n    if (child.isMesh) {\n      child.geometry.dispose()\n      if (Array.isArray(child.material)) {\n        child.material.forEach(m =&gt; disposeMaterial(m))\n      } else {\n        disposeMaterial(child.material)\n      }\n    }\n  })\n  renderer.dispose()\n  renderer.forceContextLoss()\n}\n\nfunction disposeMaterial(material) {\n  Object.values(material).forEach((value) =&gt; {\n    if (value instanceof THREE.Texture) {\n      value.dispose()\n    }\n  })\n  material.dispose()\n}\n</code></pre>\n<h2>五、优化效果总结</h2>\n<table>\n<thead>\n<tr>\n<th>优化手段</th>\n<th>FPS 提升</th>\n<th>内存变化</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>InstancedMesh</td>\n<td>+15fps</td>\n<td>-30%</td>\n</tr>\n<tr>\n<td>Draco 压缩</td>\n<td>无变化</td>\n<td>-60%</td>\n</tr>\n<tr>\n<td>按需渲染</td>\n<td>GPU占用降50%</td>\n<td>无变化</td>\n</tr>\n<tr>\n<td>纹理压缩</td>\n<td>+5fps</td>\n<td>-40%</td>\n</tr>\n<tr>\n<td>几何体合并</td>\n<td>+10fps</td>\n<td>-15%</td>\n</tr>\n</tbody>\n</table>\n<p>经过综合优化，我们的机房场景在中等配置设备上稳定运行在 <strong>45fps 以上</strong>，大屏与 3D 模型联动的流畅度提升显著。</p>\n"}})])}),[],!1,null,null,null);e.default=o.exports}}]);